import { useState, useEffect, useRef, useCallback } from "react";
import { db } from "./firebase";
import {
  collection, doc, getDoc, getDocs, addDoc, setDoc, updateDoc, deleteDoc,
  query, where, orderBy, limit, serverTimestamp, Timestamp
} from "firebase/firestore";

// ── Firebase helper — mirrors Supabase API shape ──────────────────────────────
// All collections use the same names as before for easy migration
const supabase = {
  from: (collectionName) => new FirestoreQuery(collectionName),
};

class FirestoreQuery {
  constructor(col) {
    this._col = col;
    this._filters = [];
    this._order = null;
    this._limitN = null;
    this._updates = null;
  }

  select(fields = "*") { this._fields = fields; return this; }

  eq(field, value) {
    this._filters.push({ field, op: "==", value });
    return this;
  }

  neq(field, value) {
    this._filters.push({ field, op: "!=", value });
    return this;
  }

  in(field, values) {
    this._filters.push({ field, op: "in", value: values });
    return this;
  }

  order(field, opts = {}) {
    this._order = { field, asc: opts.ascending !== false };
    return this;
  }

  limit(n) { this._limitN = n; return this; }

  async _execute() {
    const colRef = collection(db, this._col);
    const constraints = [];
    for (const f of this._filters) {
      constraints.push(where(f.field, f.op, f.value));
    }
    if (this._order) constraints.push(orderBy(this._order.field, this._order.asc ? "asc" : "desc"));
    if (this._limitN) constraints.push(limit(this._limitN));
    const snap = constraints.length > 0
      ? await getDocs(query(colRef, ...constraints))
      : await getDocs(colRef);
    const data = snap.docs.map(d => ({ id: d.id, ...d.data() }));
    return { data, error: null };
  }

  then(resolve, reject) {
    return this._execute().then(resolve, reject);
  }

  async single() {
    const res = await this._execute();
    const rows = res.data;
    if (!rows || rows.length === 0) return { data: null, error: null };
    return { data: rows[0], error: null };
  }

  async insert(rows) {
    const colRef = collection(db, this._col);
    let lastData = null;
    for (const row of rows) {
      const { id, ...rest } = row;
      const docId = id ? String(id) : null;
      if (docId) {
        await setDoc(doc(db, this._col, docId), {
          ...rest, created_at: rest.created_at || new Date().toISOString()
        });
        lastData = { id: docId, ...rest };
      } else {
        const ref = await addDoc(colRef, {
          ...rest, created_at: rest.created_at || new Date().toISOString()
        });
        lastData = { id: ref.id, ...rest };
      }
    }
    // Support .select().single() chaining after insert
    const result = { data: lastData, error: null };
    result.select = () => ({
      single: async () => ({ data: lastData, error: null })
    });
    return result;
  }

  async _doUpdate(updates) {
    const res = await this._execute();
    for (const row of (res.data || [])) {
      await updateDoc(doc(db, this._col, String(row.id)), updates);
    }
    return { error: null };
  }

  // update(data) returns an object with .eq() for chaining AND is awaitable
  update(updates) {
    const self = this;
    // Create a thenable that also has .eq() for chaining
    const thenable = {
      eq(field, value) {
        self._filters.push({ field, op: "==", value });
        return {
          then(resolve, reject) {
            self._doUpdate(updates).then(resolve).catch(reject);
          }
        };
      },
      then(resolve, reject) {
        self._doUpdate(updates).then(resolve).catch(reject);
      }
    };
    return thenable;
  }

  async upsert(rows) {
    const colRef = collection(db, this._col);
    for (const row of rows) {
      const { id, ...rest } = row;
      if (this._filters.length > 0) {
        const existing = await this._execute();
        if (existing.data && existing.data.length > 0) {
          await updateDoc(doc(db, this._col, existing.data[0].id), rest);
          return { error: null };
        }
      }
      if (id) {
        await setDoc(doc(db, this._col, String(id)), rest, { merge: true });
      } else {
        await addDoc(colRef, rest);
      }
    }
    return { error: null };
  }

  async delete() {
    const res = await this._execute();
    for (const row of (res.data || [])) {
      await deleteDoc(doc(db, this._col, String(row.id)));
    }
    return { error: null };
  }
}

// ── Multi-provider FREE AI utility ───────────────────────────────────────────
//
//  Chain: Gemini (free, 15 rpm) → Groq (free, 30 rpm) → OpenRouter free models
//
//  HOW TO GET FREE KEYS:
//  • Gemini  → https://aistudio.google.com/app/apikey          (instant, no CC)
//  • Groq    → https://console.groq.com/keys                   (instant, no CC)
//  • OpenRouter → https://openrouter.ai/keys                   (free credits, no CC)
//
//  Add multiple keys of the same provider to multiply your quota.
// ─────────────────────────────────────────────────────────────────────────────

const AI_KEYS = {
  // ── Gemini: 15 req/min, 1500 req/day FREE ─────────────────────────────────
  gemini: [
    "AIzaSyBoVY6Bsd4OcDkgH7oNh11BSorCJ9tvdZc",
    "AIzaSyAQnuAAfNB2ryG9MY8viPiCu1KJc2Vy9uY",
  ],

  // ── Groq: 30 req/min, 14400 req/day FREE (fastest inference) ──────────────
  groq: [
    "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",
  ],

  // ── OpenRouter: free models, no rate limit on free tier ───────────────────
  openrouter: [
    "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",
  ],
};

// Gemini provider
async function _callGemini(prompt, maxTokens, keys) {
  const startIdx = (() => {
    try { return parseInt(localStorage.getItem("gm_idx") || "0") % keys.length; } catch { return 0; }
  })();
  for (let i = 0; i < keys.length; i++) {
    const idx = (startIdx + i) % keys.length;
    const key = keys[idx];
    if (!key) continue;
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${key}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          contents: [{ role: "user", parts: [{ text: prompt }] }],
          generationConfig: { temperature: 0.4, maxOutputTokens: maxTokens },
        }),
      }
    );
    if (res.status === 429) { continue; } // try next key
    if (!res.ok) throw new Error(await res.text());
    const data = await res.json();
    const text = data.candidates?.[0]?.content?.parts?.[0]?.text || "";
    if (!text) throw new Error("Empty Gemini response");
    try { localStorage.setItem("gm_idx", String((idx + 1) % keys.length)); } catch {}
    return text;
  }
  throw Object.assign(new Error("RATE_LIMITED"), { provider: "gemini" });
}

// Groq provider — FREE, llama-3.3-70b, extremely fast
async function _callGroq(prompt, maxTokens, keys) {
  const startIdx = (() => {
    try { return parseInt(localStorage.getItem("gq_idx") || "0") % keys.length; } catch { return 0; }
  })();
  for (let i = 0; i < keys.length; i++) {
    const idx = (startIdx + i) % keys.length;
    const key = keys[idx];
    if (!key || key.trim() === "") continue;
    const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
      method: "POST",
      headers: { "Content-Type": "application/json", Authorization: `Bearer ${key}` },
      body: JSON.stringify({
        model: "llama-3.3-70b-versatile",
        messages: [{ role: "user", content: prompt }],
        max_tokens: Math.min(maxTokens, 32768), // Groq free supports up to 32k
        temperature: 0.4,
      }),
    });
    if (res.status === 429) { continue; }
    if (!res.ok) throw new Error(await res.text());
    const data = await res.json();
    const text = data.choices?.[0]?.message?.content || "";
    if (!text) throw new Error("Empty Groq response");
    try { localStorage.setItem("gq_idx", String((idx + 1) % keys.length)); } catch {}
    return text;
  }
  throw Object.assign(new Error("RATE_LIMITED"), { provider: "groq" });
}

// OpenRouter provider — free models available (no CC needed)
async function _callOpenRouter(prompt, maxTokens, keys) {
  for (const key of keys) {
    if (!key || key.trim() === "") continue;
    const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${key}`,
        "HTTP-Referer": window.location.origin,
        "X-Title": "VitaTrack Diet Planner",
      },
      body: JSON.stringify({
        model: "meta-llama/llama-3.3-70b-instruct:free",
        messages: [{ role: "user", content: prompt }],
        max_tokens: Math.min(maxTokens, 8192), // OpenRouter free model limit
        temperature: 0.4,
      }),
    });
    if (res.status === 429) { continue; }
    if (!res.ok) throw new Error(await res.text());
    const data = await res.json();
    const text = data.choices?.[0]?.message?.content || "";
    if (!text) throw new Error("Empty OpenRouter response");
    return text;
  }
  throw Object.assign(new Error("RATE_LIMITED"), { provider: "openrouter" });
}

// ── Master callAI — tries providers in order, stops at first success ──────────
async function callAI(prompt, maxTokens = 8000) {
  const providers = [
    { name: "Gemini",     fn: () => _callGemini(prompt, maxTokens, AI_KEYS.gemini) },
    { name: "Groq",       fn: () => _callGroq(prompt, maxTokens, AI_KEYS.groq) },
    { name: "OpenRouter", fn: () => _callOpenRouter(prompt, maxTokens, AI_KEYS.openrouter) },
  ];

  let lastErr = null;
  for (const { name, fn } of providers) {
    try {
      const rawText = await fn();
      // Clean JSON fences from response
      const text = rawText
        .replace(/^```json\s*/m, "")
        .replace(/^```\s*/m, "")
        .replace(/```\s*$/m, "")
        .trim();
      return { text, provider: name };
    } catch (e) {
      if (e.message === "RATE_LIMITED") {
        lastErr = e;
        continue; // try next provider
      }
      throw e; // real error, stop
    }
  }
  // All providers exhausted
  throw new Error("ALL_RATE_LIMITED");
}


