function getIngredients(foodName) {
  if (!foodName) return [];
  const name = foodName.trim();
  if (INGREDIENT_DB[name]) return INGREDIENT_DB[name];
  const key = Object.keys(INGREDIENT_DB).find(k =>
    k !== "_default" && (name.toLowerCase().includes(k.toLowerCase()) || k.toLowerCase().includes(name.toLowerCase()))
  );
  return key ? INGREDIENT_DB[key] : [];
}
// User plan:  { Monday: { breakfast: { time, items, totalCal, note }, ... totalDayCal } }

function normalizePlanToWeekly(plan) {
  if (!plan) return null;

  // Already 7-day format — has day name keys
  const DAYS = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"];
  if (plan["Monday"] || plan["Tuesday"]) return plan;

  // 1-day format — convert meals to 7-day
  const adminMeals = plan.meals || {};

  // Map admin meal keys → user meal keys
  const keyMap = {
    "Breakfast":     "breakfast",
    "Lunch":         "lunch",
    "Evening Snack": "eveningSnack",
    "Dinner":        "dinner",
    "Munching":      "munching",
  };

  // Convert one admin meal to user meal format
  const convertMeal = (adminMeal) => {
    if (!adminMeal) return null;
    return {
      time: adminMeal.time || "",
      items: (adminMeal.items || []).map(item => ({
        food: item.food,
        qty: item.qty,
        cal: item.cal || 0,
        healthy: item.healthy !== false,
        type: item.type || "food",
      })),
      totalCal: adminMeal.totalCal || 0,
      note: adminMeal.tip || adminMeal.note || "",
    };
  };

  // Build a single day object
  const buildDay = () => {
    const day = {};
    let totalDayCal = 0;
    for (const [adminKey, userKey] of Object.entries(keyMap)) {
      const meal = convertMeal(adminMeals[adminKey]);
      if (meal) {
        day[userKey] = meal;
        totalDayCal += meal.totalCal;
      }
    }
    day.totalDayCal = plan.totalCal || totalDayCal;
    day.water = "As per your daily target";
    day.dailyDrinks = plan.dailyDrinks || [];
    day.gutTip = plan.gutTip || "";
    return day;
  };

  // Replicate across all 7 days
  const weekly = {};
  const baseDay = buildDay();
  DAYS.forEach(d => { weekly[d] = { ...baseDay }; });
  return weekly;
}
