                      })}
                      <tr style={{ background:"#f0fdf4" }}>
                        <td colSpan={3} style={{ padding:"5px 10px", fontWeight:700, color:"#16a34a" }}>Daily Total</td>
                        <td style={{ padding:"5px 10px", fontWeight:800, color:"#16a34a" }}>
